     1→// FreeLang v6: AST Node definitions
     2→
     3→export type Expr =
     4→  | { kind: "number"; value: number }
     5→  | { kind: "string"; value: string }
     6→  | { kind: "bool"; value: boolean }
     7→  | { kind: "null" }
     8→  | { kind: "ident"; name: string }
     9→  | { kind: "binary"; op: string; left: Expr; right: Expr }
    10→  | { kind: "unary"; op: string; expr: Expr }
    11→  | { kind: "call"; callee: Expr; args: Expr[] }
    12→  | { kind: "index"; object: Expr; index: Expr }
    13→  | { kind: "member"; object: Expr; property: string }
    14→  | { kind: "assign"; target: Expr; value: Expr }
    15→  | { kind: "array"; elements: Expr[] }
    16→  | { kind: "object"; entries: { key: string; value: Expr }[] }
    17→  | { kind: "fn"; name: string | null; params: string[]; body: Stmt[] }
    18→  | { kind: "ternary"; cond: Expr; then: Expr; else: Expr }
    19→  | { kind: "if"; cond: Expr; then: Stmt[]; else: Stmt[] }
    20→  | { kind: "match"; subject: Expr; arms: MatchArm[] };
    21→
    22→export type MatchArm = { pattern: Expr | null; guard: Expr | null; body: Stmt[] };
    23→
    24→export type Stmt =
    25→  | { kind: "expr"; expr: Expr }
    26→  | { kind: "let"; name: string; mutable: boolean; init: Expr | null }
    27→  | { kind: "return"; value: Expr | null }
    28→  | { kind: "if"; cond: Expr; then: Stmt[]; else: Stmt[] | null }
    29→  | { kind: "if-let"; pattern: Expr; value: Expr; body: Stmt[]; else?: Stmt[] }
    30→  | { kind: "while"; cond: Expr; body: Stmt[] }
    31→  | { kind: "while-let"; pattern: Expr; value: Expr; body: Stmt[] }
    32→  | { kind: "for"; name: string; iter: Expr; body: Stmt[] }
    33→  | { kind: "block"; body: Stmt[] }
    34→  | { kind: "break" }
    35→  | { kind: "continue" }
    36→  | { kind: "fn"; name: string; params: string[]; body: Stmt[] }
    37→  | { kind: "print"; expr: Expr; newline: boolean }
    38→  | { kind: "try"; body: Stmt[]; catchVar: string | null; catchBody: Stmt[]; finallyBody: Stmt[] }
    39→  | { kind: "throw"; expr: Expr }
    40→  | { kind: "struct"; name: string; fields: Array<{ name: string; type: string }> }
    41→  | { kind: "import"; names: string[] | null; path: string; alias: string | null }
    42→  | { kind: "export"; stmt: Stmt }
    43→  | { kind: "multi"; stmts: Stmt[] }
    44→  | { kind: "match"; subject: Expr; arms: MatchArm[] };
    45→
    46→export type Program = { stmts: Stmt[] };
