     1→// FreeLang v6: Parser (Pratt / Recursive Descent)
     2→
     3→import { Token, TokenType as T } from "./token";
     4→import { Expr, Stmt, Program, MatchArm } from "./ast";
     5→
     6→export function parse(tokens: Token[]): Program {
     7→  let pos = 0;
     8→
     9→  function peek(): Token { return tokens[pos]; }
    10→  function advance(): Token { return tokens[pos++]; }
    11→  function expect(type: T, msg?: string): Token {
    12→    const t = advance();
    13→    if (t.type !== type) throw new Error(msg ?? `Expected ${T[type]}, got ${T[t.type]} '${t.value}' at line ${t.line}`);
    14→    return t;
    15→  }
    16→  function match(type: T): boolean { if (peek().type === type) { advance(); return true; } return false; }
    17→  function at(type: T): boolean { return peek().type === type; }
    18→
    19→  // --- Statements ---
    20→  function parseProgram(): Program {
    21→    const stmts: Stmt[] = [];
    22→    while (!at(T.EOF)) stmts.push(parseStmt());
    23→    return { stmts };
    24→  }
    25→
    26→  function parseStmt(): Stmt {
    27→    while (match(T.Semicolon)) {} // skip stray semicolons
    28→    if (at(T.EOF)) return { kind: "expr", expr: { kind: "null" } };
    29→    if (at(T.Let) || at(T.Const)) return parseLetStmt();
    30→    if (at(T.Fn)) return parseFnStmt();
    31→    if (at(T.Return)) return parseReturn();
    32→    if (at(T.If)) return parseIf();
    33→    if (at(T.While)) return parseWhile();
    34→    if (at(T.For)) return parseFor();
    35→    if (at(T.LBrace)) return parseBlock();
    36→    if (at(T.Print) || at(T.Println)) return parsePrint();
    37→    if (at(T.Break)) { advance(); match(T.Semicolon); return { kind: "break" }; }
    38→    if (at(T.Continue)) { advance(); match(T.Semicolon); return { kind: "continue" }; }
    39→    if (at(T.Try)) return parseTry();
    40→    if (at(T.Throw)) return parseThrow();
    41→    if (at(T.Struct)) return parseStruct();
    42→    if (at(T.Import)) return parseImport();
    43→    if (at(T.Export)) return parseExport();
    44→    if (at(T.Match)) return parseMatch();
    45→    return parseExprStmt();
    46→  }
    47→
    48→  function parseLetStmt(): Stmt {
    49→    const mutable = advance().type === T.Let;
    50→
    51→    // Object destructuring: let {a, b} = expr
    52→    if (at(T.LBrace)) {
    53→      advance();
    54→      const names: string[] = [];
    55→      while (!at(T.RBrace) && !at(T.EOF)) {
    56→        names.push(expect(T.Ident, "Expected destructured name").value);
    57→        match(T.Comma);
    58→      }
    59→      expect(T.RBrace);
    60→      expect(T.Assign, "Expected '=' after destructuring pattern");
    61→      const init = parseExpr();
    62→      match(T.Semicolon);
    63→      const tmp = `__d${pos}`;
    64→      return { kind: "multi", stmts: [
    65→        { kind: "let", name: tmp, mutable: false, init },
    66→        ...names.map(n => ({
    67→          kind: "let" as const, name: n, mutable,
    68→          init: { kind: "member" as const, object: { kind: "ident" as const, name: tmp }, property: n } as Expr,
    69→        }))
    70→      ]};
    71→    }
    72→
    73→    // Array destructuring: let [x, y] = expr
    74→    if (at(T.LBracket)) {
    75→      advance();
    76→      const names: string[] = [];
    77→      while (!at(T.RBracket) && !at(T.EOF)) {
    78→        names.push(expect(T.Ident, "Expected destructured name").value);
    79→        match(T.Comma);
    80→      }
    81→      expect(T.RBracket);
    82→      expect(T.Assign, "Expected '=' after destructuring pattern");
    83→      const init = parseExpr();
    84→      match(T.Semicolon);
    85→      const tmp = `__d${pos}`;
    86→      return { kind: "multi", stmts: [
    87→        { kind: "let", name: tmp, mutable: false, init },
    88→        ...names.map((n, i) => ({
    89→          kind: "let" as const, name: n, mutable,
    90→          init: { kind: "index" as const, object: { kind: "ident" as const, name: tmp }, index: { kind: "number" as const, value: i } as Expr } as Expr,
    91→        }))
    92→      ]};
    93→    }
    94→
    95→    const name = expect(T.Ident, "Expected variable name").value;
    96→    let init: Expr | null = null;
    97→    if (match(T.Assign)) init = parseExpr();
    98→    match(T.Semicolon);
    99→    return { kind: "let", name, mutable, init };
   100→  }
   101→
   102→  function parseFnStmt(): Stmt {
   103→    advance(); // fn
   104→    const name = expect(T.Ident, "Expected function name").value;
   105→    expect(T.LParen);
   106→    const params = parseParams();
   107→    expect(T.RParen);
   108→    // Skip return type annotation if present: -> Type
   109→    if (match(T.Arrow)) {
   110→      // Skip the return type - consume tokens until we hit opening brace
   111→      let depth = 0;
   112→      while (!at(T.LBrace) && !at(T.EOF)) {
   113→        const t = advance();
   114→        if (t.type === T.LBracket) depth++;
   115→        if (t.type === T.RBracket) depth--;
   116→        if (depth < 0) break;
   117→      }
   118→    }
   119→    expect(T.LBrace);
   120→    const body = parseBody();
   121→    expect(T.RBrace);
   122→    return { kind: "fn", name, params, body };
   123→  }
   124→
   125→  function parseReturn(): Stmt {
   126→    advance(); // return
   127→    let value: Expr | null = null;
   128→    if (!at(T.Semicolon) && !at(T.RBrace) && !at(T.EOF)) value = parseExpr();
   129→    match(T.Semicolon);
   130→    return { kind: "return", value };
   131→  }
   132→
   133→  function parseIf(): Stmt {
   134→    advance(); // if
   135→
   136→    // Check for if let pattern
   137→    if (at(T.Let)) {
   138→      return parseIfLet();
   139→    }
   140→
   141→    const cond = parseExpr();
   142→    expect(T.LBrace);
   143→    const then = parseBody();
   144→    expect(T.RBrace);
   145→    let else_: Stmt[] | null = null;
   146→    if (match(T.Else)) {
   147→      if (at(T.If)) {
   148→        else_ = [parseIf()];
   149→      } else {
   150→        expect(T.LBrace);
   151→        else_ = parseBody();
   152→        expect(T.RBrace);
   153→      }
   154→    }
   155→    return { kind: "if", cond, then, else: else_ };
   156→  }
   157→
   158→  function parseIfLet(): Stmt {
   159→    advance(); // let
   160→    const pattern = parseOr(); // Use parseOr to avoid consuming the = operator
   161→    expect(T.Assign);
   162→    const value = parseOr(); // Use parseOr for consistency
   163→    expect(T.LBrace);
   164→    const body = parseBody();
   165→    expect(T.RBrace);
   166→
   167→    let else_: Stmt[] | undefined;
   168→    if (match(T.Else)) {
   169→      if (at(T.LBrace)) {
   170→        expect(T.LBrace);
   171→        else_ = parseBody();
   172→        expect(T.RBrace);
   173→      } else if (at(T.If)) {
   174→        // else if pattern
   175→        else_ = [parseIf()];
   176→      }
   177→    }
   178→
   179→    return { kind: "if-let", pattern, value, body, else: else_ };
   180→  }
   181→
   182→  /**
   183→   * [v3.1] Parse if as an expression
   184→   *
   185→   * Supports: let x = if condition { value1 } else { value2 };
   186→   *
   187→   * Key difference from parseIf():
   188→   * - Must have else clause (to ensure all paths return a value)
   189→   * - Body can contain expressions (parsed as statements with implicit return)
   190→   * - Result is an Expr, not a Stmt
   191→   */
   192→  function parseIfExpr(): Expr {
   193→    advance(); // if
   194→    const cond = parseExpr();
   195→    expect(T.LBrace);
   196→    const then = parseBody();
   197→    expect(T.RBrace);
   198→
   199→    let else_: Stmt[];
   200→    if (match(T.Else)) {
   201→      if (at(T.If)) {
   202→        // else if: recursively parse as if expression
   203→        else_ = [{ kind: "expr", expr: parseIfExpr() }];
   204→      } else {
   205→        expect(T.LBrace);
   206→        else_ = parseBody();
   207→        expect(T.RBrace);
   208→      }
   209→    } else {
   210→      throw new Error("If expression must have else clause");
   211→    }
   212→
   213→    // Return as an Expr node with kind "if"
   214→    return { kind: "if", cond, then, else: else_ };
   215→  }
   216→
   217→  /**
   218→   * [v3.4] Parse match as an expression
   219→   *
   220→   * Supports: let x = match value { ... };
   221→   * Returns an Expr with kind "match"
   222→   */
   223→  function parseMatchExpr(): Expr {
   224→    advance(); // match
   225→    const subject = parseExpr();
   226→    expect(T.LBrace);
   227→    const arms: MatchArm[] = [];
   228→
   229→    while (!at(T.RBrace) && !at(T.EOF)) {
   230→      let pattern: Expr | null = null;
   231→      if (at(T.Ident) && peek().value === "_") {
   232→        advance(); // _
   233→      } else {
   234→        pattern = parseExpr();
   235→      }
   236→
   237→      // Parse optional guard clause: if condition
   238→      let guard: Expr | null = null;
   239→      if (match(T.If)) {
   240→        guard = parseExpr();
   241→      }
   242→
   243→      expect(T.FatArrow, "Expected '=>' in match arm");
   244→
   245→      // Parse body: can be expr or block
   246→      let body: Stmt[];
   247→      if (at(T.LBrace)) {
   248→        expect(T.LBrace);
   249→        body = parseBody();
   250→        expect(T.RBrace);
   251→      } else {
   252→        // Single expression as body
   253→        const expr = parseExpr();
   254→        body = [{ kind: "expr", expr }];
   255→      }
   256→
   257→      arms.push({ pattern, guard, body });
   258→      match(T.Comma);
   259→    }
   260→
   261→    expect(T.RBrace);
   262→    return { kind: "match", subject, arms } as any;
   263→  }
   264→
   265→  function parseWhile(): Stmt {
   266→    advance(); // while
   267→
   268→    // Check for while let pattern
   269→    if (at(T.Let)) {
   270→      return parseWhileLet();
   271→    }
   272→
   273→    const useParen = match(T.LParen);
   274→    const cond = parseExpr();
   275→    if (useParen) expect(T.RParen);
   276→    expect(T.LBrace);
   277→    const body = parseBody();
   278→    expect(T.RBrace);
   279→    return { kind: "while", cond, body };
   280→  }
   281→
   282→  function parseWhileLet(): Stmt {
   283→    advance(); // let
   284→    const pattern = parseOr(); // Use parseOr to avoid consuming the = operator
   285→    expect(T.Assign);
   286→    const value = parseOr(); // Use parseOr for consistency
   287→    expect(T.LBrace);
   288→    const body = parseBody();
   289→    expect(T.RBrace);
   290→
   291→    return { kind: "while-let", pattern, value, body };
   292→  }
   293→
   294→  function parseFor(): Stmt {
   295→    advance(); // for
   296→    const name = expect(T.Ident, "Expected loop variable").value;
   297→    expect(T.In, "Expected 'in'");
   298→    const iter = parseExpr();
   299→    expect(T.LBrace);
   300→    const body = parseBody();
   301→    expect(T.RBrace);
   302→    return { kind: "for", name, iter, body };
   303→  }
   304→
   305→  function parseBlock(): Stmt {
   306→    expect(T.LBrace);
   307→    const body = parseBody();
   308→    expect(T.RBrace);
   309→    return { kind: "block", body };
   310→  }
   311→
   312→  function parsePrint(): Stmt {
   313→    const newline = advance().type === T.Println;
   314→    expect(T.LParen);
   315→    const expr = parseExpr();
   316→    expect(T.RParen);
   317→    match(T.Semicolon);
   318→    return { kind: "print", expr, newline };
   319→  }
   320→
   321→  function parseTry(): Stmt {
   322→    advance(); // try
   323→    expect(T.LBrace);
   324→    const body = parseBody();
   325→    expect(T.RBrace);
   326→    let catchVar: string | null = null;
   327→    let catchBody: Stmt[] = [];
   328→    let finallyBody: Stmt[] = [];
   329→    if (match(T.Catch)) {
   330→      if (match(T.LParen)) {
   331→        catchVar = expect(T.Ident, "Expected catch variable").value;
   332→        expect(T.RParen);
   333→      }
   334→      expect(T.LBrace);
   335→      catchBody = parseBody();
   336→      expect(T.RBrace);
   337→    }
   338→    if (match(T.Finally)) {
   339→      expect(T.LBrace);
   340→      finallyBody = parseBody();
   341→      expect(T.RBrace);
   342→    }
   343→    return { kind: "try", body, catchVar, catchBody, finallyBody };
   344→  }
   345→
   346→  function parseThrow(): Stmt {
   347→    advance(); // throw
   348→    const expr = parseExpr();
   349→    match(T.Semicolon);
   350→    return { kind: "throw", expr };
   351→  }
   352→
   353→  function parseStruct(): Stmt {
   354→    advance(); // struct
   355→    const name = expect(T.Ident).value;
   356→    expect(T.LBrace);
   357→    const fields: Array<{ name: string; type: string }> = [];
   358→    while (!at(T.RBrace) && !at(T.EOF)) {
   359→      const fieldName = expect(T.Ident).value;
   360→      // Type annotation: "x: i32" or just "x" defaults to "any"
   361→      let fieldType = "any";
   362→      if (at(T.Colon)) {
   363→        advance();
   364→        fieldType = expect(T.Ident).value;
   365→      }
   366→      fields.push({ name: fieldName, type: fieldType });
   367→      match(T.Comma);
   368→    }
   369→    expect(T.RBrace);
   370→    return { kind: "struct", name, fields };
   371→  }
   372→
   373→  function parseImport(): Stmt {
   374→    advance(); // import
   375→    if (at(T.LBrace)) {
   376→      // import { name1, name2 } from "path"
   377→      advance(); // {
   378→      const names: string[] = [];
   379→      while (!at(T.RBrace) && !at(T.EOF)) {
   380→        names.push(expect(T.Ident, "Expected import name").value);
   381→        match(T.Comma);
   382→      }
   383→      expect(T.RBrace);
   384→      expect(T.From, "Expected 'from'");
   385→      const p = expect(T.String, "Expected module path").value;
   386→      match(T.Semicolon);
   387→      return { kind: "import", names, path: p, alias: null };
   388→    } else {
   389→      // import "path" or import "path" as Alias
   390→      const p = expect(T.String, "Expected module path").value;
   391→      let alias: string | null = null;
   392→      if (match(T.As)) alias = expect(T.Ident, "Expected alias name").value;
   393→      match(T.Semicolon);
   394→      return { kind: "import", names: null, path: p, alias };
   395→    }
   396→  }
   397→
   398→  function parseExport(): Stmt {
   399→    advance(); // export
   400→    if (at(T.Fn)) return { kind: "export", stmt: parseFnStmt() };
   401→    if (at(T.Let) || at(T.Const)) return { kind: "export", stmt: parseLetStmt() };
   402→    throw new Error(`Expected fn or let after export at line ${peek().line}`);
   403→  }
   404→
   405→  function parseMatch(): Stmt {
   406→    advance(); // match
   407→    const subject = parseExpr();
   408→    expect(T.LBrace);
   409→    const arms: MatchArm[] = [];
   410→    while (!at(T.RBrace) && !at(T.EOF)) {
   411→      let pattern: Expr | null = null;
   412→      if (at(T.Ident) && peek().value === "_") {
   413→        advance(); // _
   414→      } else {
   415→        pattern = parseExpr();
   416→      }
   417→
   418→      // Parse optional guard clause: if condition
   419→      let guard: Expr | null = null;
   420→      if (match(T.If)) {
   421→        guard = parseExpr();
   422→      }
   423→
   424→      expect(T.FatArrow, "Expected '=>' in match arm");
   425→      let body: Stmt[];
   426→      if (at(T.LBrace)) {
   427→        expect(T.LBrace);
   428→        body = parseBody();
   429→        expect(T.RBrace);
   430→      } else {
   431→        body = [parseStmt()];
   432→      }
   433→      arms.push({ pattern, guard, body });
   434→      match(T.Comma);
   435→    }
   436→    expect(T.RBrace);
   437→    return { kind: "match", subject, arms };
   438→  }
   439→
   440→  function parseExprStmt(): Stmt {
   441→    const expr = parseExpr();
   442→    match(T.Semicolon);
   443→    return { kind: "expr", expr };
   444→  }
   445→
   446→  // --- Expressions (Pratt) ---
   447→  function parseExpr(): Expr { return parseAssign(); }
   448→
   449→  function parseAssign(): Expr {
   450→    let left = parseOr();
   451→    if (at(T.Assign) || at(T.PlusAssign) || at(T.MinusAssign) || at(T.StarAssign) || at(T.SlashAssign)) {
   452→      const op = advance();
   453→      const right = parseAssign();
   454→      if (op.type === T.Assign) return { kind: "assign", target: left, value: right };
   455→      const binOp = op.value[0]; // +, -, *, /
   456→      return { kind: "assign", target: left, value: { kind: "binary", op: binOp, left, right } };
   457→    }
   458→    return left;
   459→  }
   460→
   461→  function parseOr(): Expr {
   462→    let left = parseAnd();
   463→    while (match(T.Or)) left = { kind: "binary", op: "||", left, right: parseAnd() };
   464→    return left;
   465→  }
   466→
   467→  function parseAnd(): Expr {
   468→    let left = parseEquality();
   469→    while (match(T.And)) left = { kind: "binary", op: "&&", left, right: parseEquality() };
   470→    return left;
   471→  }
   472→
   473→  function parseEquality(): Expr {
   474→    let left = parseComparison();
   475→    while (at(T.Eq) || at(T.Neq)) {
   476→      const op = advance().value;
   477→      left = { kind: "binary", op, left, right: parseComparison() };
   478→    }
   479→    return left;
   480→  }
   481→
   482→  function parseComparison(): Expr {
   483→    let left = parseAddition();
   484→    while (at(T.Lt) || at(T.Gt) || at(T.Lte) || at(T.Gte)) {
   485→      const op = advance().value;
   486→      left = { kind: "binary", op, left, right: parseAddition() };
   487→    }
   488→    return left;
   489→  }
   490→
   491→  function parseAddition(): Expr {
   492→    let left = parseMultiplication();
   493→    while (at(T.Plus) || at(T.Minus)) {
   494→      const op = advance().value;
   495→      left = { kind: "binary", op, left, right: parseMultiplication() };
   496→    }
   497→    return left;
   498→  }
   499→
   500→  function parseMultiplication(): Expr {
   501→    let left = parseUnary();
   502→    while (at(T.Star) || at(T.Slash) || at(T.Percent)) {
   503→      const op = advance().value;
   504→      left = { kind: "binary", op, left, right: parseUnary() };
   505→    }
   506→    return left;
   507→  }
   508→
   509→  function parseUnary(): Expr {
   510→    // Handle unary operators: -, !, &, *
   511→    if (at(T.Minus) || at(T.Not) || at(T.Ampersand) || at(T.Star)) {
