   546→      case T.Bool: advance(); return { kind: "bool", value: t.value === "true" };
   547→      case T.Null: advance(); return { kind: "null" };
   548→      case T.Ident: {
   549→        advance();
   550→        // Single-param arrow: x => expr
   551→        if (at(T.FatArrow)) {
   552→          advance();
   553→          if (at(T.LBrace)) {
   554→            expect(T.LBrace);
   555→            const body = parseBody();
   556→            expect(T.RBrace);
   557→            return { kind: "fn", name: null, params: [t.value], body };
   558→          }
   559→          const expr = parseAssign();
   560→          return { kind: "fn", name: null, params: [t.value], body: [{ kind: "return", value: expr }] };
   561→        }
   562→        return { kind: "ident", name: t.value };
   563→      }
   564→      case T.LParen: {
   565→        // Try arrow function: (params) => body
   566→        const savedPos = pos;
   567→        advance(); // (
   568→
   569→        // Check for empty parens arrow: () => ...
   570→        if (at(T.RParen)) {
   571→          const rp = pos;
   572→          advance(); // )
   573→          if (at(T.FatArrow)) {
   574→            advance(); // =>
   575→            return parseArrowBody([]);
   576→          }
   577→          // Not arrow, backtrack
   578→          pos = savedPos;
   579→          advance();
   580→          const expr = parseExpr();
   581→          expect(T.RParen);
   582→          return expr;
   583→        }
   584→
   585→        // Try parsing as ident list for arrow function
   586→        let isArrow = true;
   587→        const params: string[] = [];
   588→        const tryPos = pos;
   589→        while (!at(T.RParen) && !at(T.EOF)) {
   590→          if (!at(T.Ident)) { isArrow = false; break; }
   591→          params.push(advance().value);
   592→          if (!at(T.RParen)) {
   593→            if (!match(T.Comma)) { isArrow = false; break; }
   594→          }
   595→        }
   596→        if (isArrow && at(T.RParen)) {
   597→          advance(); // )
   598→          if (at(T.FatArrow)) {
   599→            advance(); // =>
   600→            return parseArrowBody(params);
   601→          }
   602→        }
   603→
   604→        // Not arrow, backtrack and parse as grouped expression
   605→        pos = savedPos;
   606→        advance(); // (
   607→        const expr = parseExpr();
   608→        expect(T.RParen);
   609→        return expr;
   610→      }
   611→      case T.LBracket: return parseArrayLiteral();
   612→      case T.LBrace: return parseObjectLiteral();
   613→      case T.Fn: return parseFnExpr();
   614→      case T.If: return parseIfExpr();
   615→      case T.Match: return parseMatchExpr();
   616→      default: throw new Error(`Unexpected token '${t.value}' at line ${t.line}:${t.col}`);
   617→    }
   618→  }
   619→
   620→  function parseArrowBody(params: string[]): Expr {
   621→    if (at(T.LBrace)) {
   622→      expect(T.LBrace);
   623→      const body = parseBody();
   624→      expect(T.RBrace);
   625→      return { kind: "fn", name: null, params, body };
   626→    }
   627→    const expr = parseAssign();
   628→    return { kind: "fn", name: null, params, body: [{ kind: "return", value: expr }] };
   629→  }
   630→
   631→  function parseArrayLiteral(): Expr {
   632→    advance(); // [
   633→    const elements: Expr[] = [];
   634→    while (!at(T.RBracket) && !at(T.EOF)) {
   635→      elements.push(parseExpr());
   636→      match(T.Comma);
   637→    }
   638→    expect(T.RBracket);
   639→    return { kind: "array", elements };
   640→  }
   641→
   642→  function parseObjectLiteral(): Expr {
   643→    advance(); // {
   644→    const entries: { key: string; value: Expr }[] = [];
   645→    while (!at(T.RBrace) && !at(T.EOF)) {
   646→      const key = expect(T.Ident, "Expected key").value;
   647→      expect(T.Colon);
   648→      const value = parseExpr();
   649→      entries.push({ key, value });
   650→      match(T.Comma);
   651→    }
   652→    expect(T.RBrace);
   653→    return { kind: "object", entries };
   654→  }
   655→
   656→  function parseFnExpr(): Expr {
   657→    advance(); // fn
   658→    let name: string | null = null;
   659→    if (at(T.Ident)) name = advance().value;
   660→    expect(T.LParen);
   661→    const params = parseParams();
   662→    expect(T.RParen);
   663→    expect(T.LBrace);
   664→    const body = parseBody();
   665→    expect(T.RBrace);
   666→    return { kind: "fn", name, params, body };
   667→  }
   668→
   669→  function parseParams(): string[] {
   670→    const params: string[] = [];
   671→    while (!at(T.RParen) && !at(T.EOF)) {
   672→      const paramName = expect(T.Ident, "Expected parameter name").value;
   673→      params.push(paramName);
   674→      // Skip type annotation if present: name: Type
   675→      if (match(T.Colon)) {
   676→        // Skip the type - consume tokens until we hit comma or RParen
   677→        let depth = 0;
   678→        while (!at(T.Comma) && !at(T.RParen) && !at(T.EOF)) {
   679→          const t = advance();
   680→          // Handle nested brackets if needed (for complex types)
   681→          if (t.type === T.LBracket) depth++;
   682→          if (t.type === T.RBracket) depth--;
   683→          if (depth < 0) break;
   684→        }
   685→      }
   686→      match(T.Comma);
   687→    }
   688→    return params;
   689→  }
   690→
   691→  function parseBody(): Stmt[] {
   692→    const stmts: Stmt[] = [];
   693→    while (!at(T.RBrace) && !at(T.EOF)) stmts.push(parseStmt());
